SELECT COUNT(DISTINCT patient_id)
FROM health_indicators
WHERE indicator_name = 'blood pressure';

SELECT AVG(indicator_value) AS average_blood_pressure
FROM health_indicators
WHERE indicator_name = 'blood pressure';

SELECT ROUND(h.indicator_value) AS rounded_indicator_value
FROM health_indicators h
JOIN user_access a ON h.patient_id = a.patient_id;

SELECT MIN(indicator_value) 
FROM health_indicators
WHERE patient_id = 1001 AND indicator_name = 'blood pressure';

SELECT indicator_name, indicator_value
FROM health_indicators
WHERE indicator_date > '2023-05-01';
